#include<bits/stdc++.h>
using namespace std;
int n,d;
int f[105][47000][6];
int a[105];
int b[7];
char s[105];
inline int max(int x,int y)
{
    return (x>y?x:y);
}
int dfs(int x,int gezi,int cangku)
{
    if(f[x][gezi][cangku]!=-1)
    {
        return f[x][gezi][cangku];
    }
    if(x==d+2)
    {
        return 0;
    }
    f[x][gezi][cangku]=0;
    if(cangku==0)
    {
        f[x][gezi][cangku]=dfs(x+1,gezi,a[x]);
    }
    int tmp,sum;
    for(int i=1;i<=n;i++)
    {
        tmp=gezi;
        for(int j=1;j<=6;j++)
        {
            b[j]=tmp%6;
            tmp/=6;
        }
        if(b[i]==0)
        {
            if(x!=d+1)
            {
                b[i]=a[x];
                int sum1=0;
                if(b[i-1]==b[i]||b[i+1]==b[i])
                {
                    int l=i,r=i;
                    while(l>1&&b[l-1]==b[i])
                    {
                        l--;
                        b[l]=0;
                    }
                    while(r<n&&b[r+1]==b[i])
                    {
                        r++;
                        b[r]=0;
                    }
                    sum1+=(r-l+1)*(1<<(b[i]));
                    if(b[i]==5)
                    {
                        b[i]=0;
                    }
                    else
                    {
                        b[i]++;
                    }
                    if(b[i]!=0&&(b[i-1]==b[i]||b[i+1]==b[i]))
                    {
                        int l=i,r=i;
                        while(l>1&&b[l-1]==b[i])
                        {
                            l--;
                            b[l]=0;
                        }
                        while(r<n&&b[r+1]==b[i])
                        {
                            r++;
                            b[r]=0;
                        }
                        sum1+=(r-l+1)*(1<<(b[i]));
                        if(b[i]==5)
                        {
                            b[i]=0;
                        }
                        else
                        {
                            b[i]++;
                        }
                    }
                }
                sum=0;
                for(int j=6;j>=1;j--)
                {
                    sum=sum*6+b[j];
                }
                f[x][gezi][cangku]=max(f[x][gezi][cangku],dfs(x+1,sum,cangku)+sum1);
            }
            if(cangku)
            {
                if(x!=d+1)
                {
                    tmp=gezi;
                    for(int j=1;j<=6;j++)
                    {
                        b[j]=tmp%6;
                        tmp/=6;
                    }
                }
                b[i]=cangku;
                int sum1=0;
                if(b[i-1]==b[i]||b[i+1]==b[i])
                {
                    int l=i,r=i;
                    while(l>1&&b[l-1]==b[i])
                    {
                        l--;
                        b[l]=0;
                    }
                    while(r<n&&b[r+1]==b[i])
                    {
                        r++;
                        b[r]=0;
                    }
                    sum1+=(r-l+1)*(1<<(b[i]));
                    if(b[i]==5)
                    {
                        b[i]=0;
                    }
                    else
                    {
                        b[i]++;
                    }
                    if(b[i]!=0&&(b[i-1]==b[i]||b[i+1]==b[i]))
                    {
                        int l=i,r=i;
                        while(l>1&&b[l-1]==b[i])
                        {
                            l--;
                            b[l]=0;
                        }
                        while(r<n&&b[r+1]==b[i])
                        {
                            r++;
                            b[r]=0;
                        }
                        sum1+=(r-l+1)*(1<<(b[i]));
                        if(b[i]==5)
                        {
                            b[i]=0;
                        }
                        else
                        {
                            b[i]++;
                        }
                    }
                }
                sum=0;
                for(int j=6;j>=1;j--)
                {
                    sum=sum*6+b[j];
                }
                f[x][gezi][cangku]=max(f[x][gezi][cangku],dfs(x,sum,0)+sum1);
            }
        }
    }
    return f[x][gezi][cangku];
}
int main()
{
    scanf("%d%d%s",&n,&d,s+1);
    for(int i=1;i<=d+1;i++)
    {
        for(int j=0;j<=46656;j++)
        {
            for(int k=0;k<=5;k++)
            {
                f[i][j][k]=-1;
            }
        }
    }
    for(int i=1;i<=d;i++)
    {
        a[i]=s[i]-'0';
    }
    printf("%d",dfs(1,0,0));
    return 0;
}
